c
unsigned char *bytes = (unsigned char *)&word;
for (int i = byte_offset; i < 8; i++) {
if (bytes_read >= max_len) break;         // length guard
if (bytes[i] == '\0') { found_null=1; break; }
out[bytes_read++] = (char)bytes[i];       // copy to output
}

c
while (bytes_read < max_len && !found_null) {
errno = 0;
long word = ptrace(PTRACE_PEEKDATA, pid, aligned_addr, NULL);
if (word == -1L && errno != 0) return -1;   // → ERROR path
// ... scan bytes ...
aligned_addr += 8;
byte_offset = 0;
}
out[bytes_read] = '\0';    // always null-terminate output
return bytes_read;         // 0..max_len  (-1 on error)
